INSERT OR IGNORE INTO "stories" ("id", "title", "description", "difficulty", "durationMin", "isActive", "createdAt", "updatedAt") VALUES ('cmntl1qjm0002pxaouxrbfz4g', 'Il Mistero della Birra Scomparsa', 'Una serata normale al pub si trasforma in un enigma quando la birra speciale scompare. Trovate indizi e risolvete gli enigmi prima che chiuda!', 'medium', 60, 1, 1775866475939, 1775866475939);
INSERT OR IGNORE INTO "stories" ("id", "title", "description", "difficulty", "durationMin", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvh0001hw4qzefi2lkh', 'La Garduña', 'Una società criminale sorta in Spagna nel 1412 con struttura piramidale. Seguite la loro storia attraverso enigmi e codici.', 'hard', 90, 1, 1781558354142, 1781558354142);
INSERT OR IGNORE INTO "stories" ("id", "title", "description", "difficulty", "durationMin", "isActive", "createdAt", "updatedAt") VALUES ('cmqpd193t0006a3li9lgii2xm', 'Storia Test', 'Questo è una storia test, la prima creata dalla sezione creator', 'medium', 60, 1, 1782141498714, 1782141498714);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmntl1qjr0004pxaogqofl8zq', 'cmntl1qjm0002pxaouxrbfz4g', 1, 'Step 1: L''Inizio del Mistero', 'La birra speciale è scomparsa dal bancone. Indagate nell''area del bar per trovare il primo indizio.', 'Quale ingrediente segreto viene menzionato nel biglietto trovato sotto il bancone?', 'text', NULL, NULL, 1, 1775866475943, 1775866475943);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmntl1qju0006pxaoqhx25hpw', 'cmntl1qjm0002pxaouxrbfz4g', 2, 'Step 2: Le Tracce del Barista', 'Il barista ha lasciato delle strane note. Trovate il significato di questi simboli enigmatici.', 'Qual è la somma dei numeri scritti sul tovagliolo del barista?', 'text', NULL, NULL, 1, 1775866475946, 1775866475946);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmntl1qk90008pxaof0l7382l', 'cmntl1qjm0002pxaouxrbfz4g', 3, 'Step 3: Il Codice Frigorifero', 'Il frigorifero è bloccato con un codice numerico. Usate gli indizi trovati per aprirlo.', 'Qual è il codice a 4 cifre che apre il frigorifero?', 'text', NULL, NULL, 1, 1775866475961, 1775866475961);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmntl1qkh000apxaortzvz2nk', 'cmntl1qjm0002pxaouxrbfz4g', 4, 'Step 4: La Rivelazione Finale', 'Avete trovato la birra! Ma c''è un ultimo enigma da risolvere per completare la missione.', 'Chi è il vero responsabile della scomparsa della birra speciale?', 'text', NULL, NULL, 1, 1775866475970, 1775866475970);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi0002hw4q7wxd0jbf', 'cmqfpufvh0001hw4qzefi2lkh', 1, 'FASE 1 - Piramide di parole', 'A VOLTE CI SONO MOMENTI IMPORTANTI NELLA PROPRIA VITA CHE TUTTI ASPETTANNO CON ANSIA E CHE SPESSO NON CAPITANO MAI. MA PER VOI NON E’ COSI’ ED OGGI E’ UNO DI QUESTI. AL COSPETTO DI PERSONAGGI IMPORTANTI VI TROVERETE A DECIDERE DEL VOSTRO FUTURO, FUTURO IN CUI POTRETE METTERE LE ALI AI PIEDI FINO AD ARRIVARE, CHISSA’, AI PIANI ALTI DI QUESTA ORGANIZZAZIONE CHIARAMENTE PIRAMIDALE CHE DA’, ATTRAVERSO IL SACRIFICIO, LA POSSIBILITA’ A TUTTI DI EMERGERE. NON SONO VIETATI INFATTI SALTI TALI DA POTER FAR SI CHE VI RITROVIATE IN MEN CHE NON SI DICA DOVE NEANCHE LA VOSTRA PIU’ FERVIDA IMMAGINAZIONE PUO’ SPERARE. POTRETE FINALMENTE CAMBIARE VITA E NON DOVER PIU’ SOFFRIRE PER AFFITTI O BOLLETTINI TROPPO SALATI, SOFFRIRE PER IL MUTUO O PERCHE’ NON SI RIESCE AD ARRIVARE A FINE MESE PER COLPA DI UNO STATO CHE STRITOLA VOI E I VOSTRI CARI. NON RIMARRETE MAI PIU’ SVEGLI LA NOTTE PENSANDO DI NON FARCELA. QUA TROVERETE AMICIZIA, CONFORTO, SINCERITA’, E PER NOI QUESTI SONO TUTTI VINCOLI SALDATI CON IL SANGUE. IN CAMBIO DELLA VOSTRA ASSOLUTA DEVOZIONE ALL’ORGANIZZAZIONE SARETE SEMPRE PROTETTI, SARETE COCCOLATI E SCALDATI COME PUO’ FARE IL FOCOLARE DI CASA PROPRIA O L’ABBRACCIO DI UNA MADRE. SI, PER VOI SAREMO COME UNA FAMIGLIA. LA VOSTRA FAMIGLIA! ONORE E SANGUE!

Questa società alla vecchia
garduna non è del tutto uguale,
ma entrambe hanno una
organizzazione piramidale,
prendo spunto da questa cosa
per farvi cercare in questo
scritto qualcosa; una piramide
di parole, è proprio quello che ci
vuole. Otto sono da trovare,
scrivetele e avanti potrete
andare!


Piramide di parole:
Aggiungere ad ogni parola una lettera formando un’altra parola. La lettera può essere all’inizio, in mezzo alla fine ecc, ecc.
Esempio pratico 8 parole
E
RE
TRE
OTRE
OLTRE
COLTRE
COLTURE
COLATURE', 'Costruire una sequenza di 8 parole dove ogni parola si ottiene aggiungendo una sola lettera alla precedente', 'multi_text_ordered', 8, '{"fields":[{"position":1,"placeholder":"Parola 1"},{"position":2,"placeholder":"Parola 2"},{"position":3,"placeholder":"Parola 3"},{"position":4,"placeholder":"Parola 4"},{"position":5,"placeholder":"Parola 5"},{"position":6,"placeholder":"Parola 6"},{"position":7,"placeholder":"Parola 7"},{"position":8,"placeholder":"Parola 8"}]}', 1, 1781558354142, 1782161079608);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi000ehw4qg2m8vj9f', 'cmqfpufvh0001hw4qzefi2lkh', 2, 'FASE 2 - La Sequenza del Giuramento', 'VI SIETE SCALDATI? BEH DI ANDARE AVANTI VE LO SIETE PROPRIO MERITATI LEGGETE QUESTE FRASI SCOMBINATE, CHE VANNO SUBITO RIORDINATE; FATE QUINDI UN PRIMO SFORZO PER FAR SI CHE ABBIA SENSO IL DISCORSO. SCRIVETE QUINDI DI OGNI GRUPPO I NUMERI DELLA GIUSTA SEQUENZA, PERCHÉ NON POTRETE ANDARE AVANTI SENZA!', 'Riordinare correttamente le frasi scomposte all’interno di 4 gruppi distinti (A, B, C, D) e inserire per ciascun gruppo la sequenza numerica corretta', 'multi_group_ordered_numbers', 19, '{"groups":[{"label":"A","fieldCount":6},{"label":"B","fieldCount":4},{"label":"C","fieldCount":5},{"label":"D","fieldCount":4}]}', 1, 1781558354142, 1782161147665);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi0011hw4q437et04u', 'cmqfpufvh0001hw4qzefi2lkh', 3, 'FASE 2 - L''Ordine del Giuramento', 'ORA DITEMI L’ORDINE ESATTO
DEI QUATTRO FOGLI
VELOCI COME IL VENTO
PER COMPORRE IL VOSTRO BEL GIURAMENTO!', 'Ordinare correttamente i 4 gruppi (A, B, C, D) per ricostruire la sequenza narrativa completa del giuramento', 'ordered_sequence_letters', 4, '{"elements":["A","B","C","D"],"fieldCount":4}', 1, 1781558354142, 1782161248043);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi0019hw4qexqp7tgg', 'cmqfpufvh0001hw4qzefi2lkh', 4, 'FASE 3 - Il Codice della Garduña', 'MOLTO BENE, ANDIAMO AVANTI,
ORA STATE ATTENTI TUTTI QUANTI:
UN CODICE SEGRETO VI VOGLIO DARE
E VOI LO DOVRETE UTILIZZARE!
EGUENDO IL GIUSTO ORDINE DEL GIURAMENTO,
RIUSCIRETE NELLA COSA IN UN MOMENTO.
IL CODICE TRE PAROLE VI DARÀ,
FORZA, NON MI FATE DUBITARE
DELLE VOSTRE CAPACITÀ!', 'Usare l’ordine corretto dei fogli già ricostruito nella fase precedente e la legenda simboli per decodificare una frase finale composta da 3 parole', 'text_single', 1, NULL, 1, 1781558354142, 1782161447596);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi001ehw4q8hhffluv', 'cmqfpufvh0001hw4qzefi2lkh', 5, 'FASE 4 - L''Albero della Scienza', 'ECCO A VOI L’ALBERO DELLA SCIENZA!
SPERO PRENDIATE SUBITO COSCIENZA
CHE PER ESSERE DEGNI DI QUESTA SOCIETÀ
BISOGNA ESSERE FORTI E SENZA PIETÀ.
NESSUNO DAL VOSTRO CONSORTO ORA VI DISTOGLIE,
FACILE DOMANDA: QUANTE SONO TUTTE LE FOGLIE?
DATEMI IL NUMERO ESATTO PER RESTARE FUORI,
DA COLORO CHE SONO INFAMI E TRADITORI.', 'Osservare l’immagine dell’albero e contare il numero totale di foglie, escludendo gli altri elementi presenti', 'number_single', 1, NULL, 1, 1781558354142, 1782163656341);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi001khw4qgad1urnz', 'cmqfpufvh0001hw4qzefi2lkh', 6, 'FASE 4 - La Parola del Giuramento', 'VIDI UNA BARCA DOVE STAVANO TRE VECCHI MARINAI CHE MI DOMANDARONO COSA STAVO CERCANDO. IO GLI RISPOSI: SANGUE E ONORE. MI DISSERO DI SEGUIRLI CHE L’AVREI TROVATO.

ARRIVAMMO ALL’ISOLA DI FAVIGNANA DOPO TRE GIORNI E TRE NOTTI DI NAVIGAZIONE. LÌ SULLA MIA DESTRA VIDI UN CASTELLO DOVE C’ERANO DUE LEONI INCATENATI A UNA CATENA DI VENTIQUATTRO MAGLIE E DOPO MI ACCORSI CHE C’ERA UNA SCALA DI MARMO DI VENTIQUATTRO GRADINI.

IN CIMA A QUESTA SCALA SULLA MIA DESTRA TROVAI TRE STANZE. ENTRAI NELLA PRIMA E VI TROVAI UN VECCHIO CON LA BARBA: ERA SAN MICHELE ARCANGELO. ENTRAI NELLA SECONDA STANZA E VI TROVAI UNA DONNA VESTITA TUTTA DI NERO ERA NOSTRA SANTA SORELLA ELISABETTA.

ENTRAI NELLA TERZA STANZA E VI TROVAI UNA CASSA DI NOCE FINISSIMA: L’HO APERTA E VI TROVAI UN PUGNALE E LÌ HO GIURATO ETERNA FEDELTÀ ALL’ONORATA SOCIETÀ.', 'Utilizzare il numero corretto ottenuto nello step precedente e applicarlo al testo del giuramento per ricavare una parola precisa', 'text_single', 1, NULL, 1, 1781558354142, 1782163865451);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi001qhw4qzg2d9j2y', 'cmqfpufvh0001hw4qzefi2lkh', 7, 'I Punti di Favignana', 'Il tatuaggio dei tre punti indicava l''appartenenza alla Garduña. Per ogni luogo trovate una parola che formi un''espressione comune con PUNTO (es: PUNTO VENDITA). Tre luoghi non hanno nessuna associazione: lasciateli vuoti.', 'Per ogni luogo inserite la parola da abbinare a PUNTO. Lasciate vuoti i luoghi per cui non esiste un''associazione.', 'list_text_with_empty_allowed', 13, '{"items":[{"position":1,"label":"PUNTA FARAGLIONE","emptyAllowed":false},{"position":2,"label":"PUNTA FERRO","emptyAllowed":false},{"position":3,"label":"PUNTA SOTTILE","emptyAllowed":false},{"position":4,"label":"SCALO CAVALLO","emptyAllowed":false},{"position":5,"label":"PUNTA SAN NICOLA","emptyAllowed":false},{"position":6,"label":"PUNTA GALERA","emptyAllowed":false},{"position":7,"label":"CASTELLO DI SANTA CATERINA","emptyAllowed":true},{"position":8,"label":"LIDO BURRONE","emptyAllowed":false},{"position":9,"label":"PALAZZO FLORIO","emptyAllowed":false},{"position":10,"label":"CALA AZZURRA","emptyAllowed":true},{"position":11,"label":"CALA ROSSA","emptyAllowed":false},{"position":12,"label":"BUE MARINO","emptyAllowed":false},{"position":13,"label":"TONNARA","emptyAllowed":true}]}', 1, 1781558354142, 1781558354142);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi0028hw4qhq5sawl3', 'cmqfpufvh0001hw4qzefi2lkh', 8, 'Il Giudizio di San Michele', 'San Michele Arcangelo regge una bilancia (equilibrio), una spada (discernimento) e sconfigge il drago (il male). Solo uno dei luoghi trovati porta al tesoro.', 'Quale luogo di Favignana porta al tesoro?', 'text_single', 1, NULL, 1, 1781558354142, 1781558354142);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi002dhw4q89lpfgv6', 'cmqfpufvh0001hw4qzefi2lkh', 9, 'La Scacchiera di Polibio', 'Polibio inventò una scacchiera 5x5 per codificare le lettere in coppie numeriche. Nel testo ricompaiono parole già incontrate nel gioco. Convertitele con la scacchiera e trovate i numeri delle caldaie.', 'Usando la scacchiera di Polibio, trovate i due numeri delle caldaie. Le parole chiave sono ALI e SALTI. I numeri cercati compaiono in entrambe le parole.', 'multi_number_unordered', 2, '{"fieldCount":2}', 1, 1781558354142, 1781558354142);
INSERT OR IGNORE INTO "story_steps" ("id", "storyId", "stepNumber", "title", "description", "question", "answerType", "inputCount", "inputConfig", "isActive", "createdAt", "updatedAt") VALUES ('cmqfpufvi002khw4qjq8y32g3', 'cmqfpufvh0001hw4qzefi2lkh', 10, 'La Frase Diversa', 'Due caldaie, 24 frasi in totale. Una sola frase si distingue per una proprietà oggettiva e verificabile. Trovatela, indicate caldaia e numero, e motivate la scelta.', 'Quale frase è oggettivamente diversa dalle altre? Indicate: caldaia (11 o 24), numero frase (1-12), motivazione.', 'structured_choice_with_reason', 3, '{"fields":[{"key":"caldaia","type":"select","options":["11","24"]},{"key":"frase","type":"number","min":1,"max":12},{"key":"motivazione","type":"text"}]}', 1, 1781558354142, 1781558354142);
